import{b as i,a as t,_ as a}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as n,o as s,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"Gestion de l’authentification et des appareils connectés","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Safety/authentication-and-login-devices.md","filePath":"fr-FR/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),l={name:"fr-FR/Safety/authentication-and-login-devices.md"};function d(c,e,u,p,h,f){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="gestion-de-l-authentification-et-des-appareils-connectes" tabindex="-1">Gestion de l’authentification et des appareils connectés <a class="header-anchor" href="#gestion-de-l-authentification-et-des-appareils-connectes" aria-label="Permalink to &quot;Gestion de l’authentification et des appareils connectés&quot;">​</a></h1><p>La gestion de l’authentification permet de suivre les connexions, les sessions actives et les appareils connectés au panneau ou aux pages utilisateur.</p><h2 id="connexion-administrateur" tabindex="-1">Connexion administrateur <a class="header-anchor" href="#connexion-administrateur" aria-label="Permalink to &quot;Connexion administrateur&quot;">​</a></h2><p>L’administrateur se connecte depuis l’écran de connexion du panneau pour gérer les fichiers et paramètres.</p><p><img src="'+i+'" alt="Connexion administrateur" loading="lazy"></p><p>Le compte administrateur dispose de droits élevés. Protégez soigneusement ses identifiants.</p><h2 id="connexion-utilisateur" tabindex="-1">Connexion utilisateur <a class="header-anchor" href="#connexion-utilisateur" aria-label="Permalink to &quot;Connexion utilisateur&quot;">​</a></h2><p>Un écran de connexion utilisateur est également disponible.</p><p><img src="'+t+'" alt="Connexion utilisateur" loading="lazy"></p><p>Si vous utilisez l’upload public ou un accès limité, la connexion utilisateur aide à identifier qui a effectué chaque action.</p><h2 id="ecran-d-authentification" tabindex="-1">Écran d’authentification <a class="header-anchor" href="#ecran-d-authentification" aria-label="Permalink to &quot;Écran d’authentification&quot;">​</a></h2><p>L’écran de gestion affiche les sessions et appareils connectés.</p><p><img src="'+a+'" alt="Gestion de l’authentification" loading="lazy"></p><h2 id="ce-qu-il-faut-verifier" tabindex="-1">Ce qu’il faut vérifier <a class="header-anchor" href="#ce-qu-il-faut-verifier" aria-label="Permalink to &quot;Ce qu’il faut vérifier&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Champ</th><th>Description</th></tr></thead><tbody><tr><td>Appareil connecté</td><td>Appareils avec session active</td></tr><tr><td>IP / localisation</td><td>Indication de l’origine de l’accès</td></tr><tr><td>Dernier accès</td><td>Aide à savoir si l’appareil est encore utilisé</td></tr><tr><td>Révoquer</td><td>Ferme une session ancienne ou suspecte</td></tr></tbody></table><h2 id="si-vous-voyez-quelque-chose-de-suspect" tabindex="-1">Si vous voyez quelque chose de suspect <a class="header-anchor" href="#si-vous-voyez-quelque-chose-de-suspect" aria-label="Permalink to &quot;Si vous voyez quelque chose de suspect&quot;">​</a></h2><ol><li>Révoquez la session de l’appareil.</li><li>Changez le mot de passe administrateur et les tokens associés.</li><li>Vérifiez les identifiants Cloudflare, GitHub et des canaux de stockage.</li><li>Régénérez les API Tokens si nécessaire.</li></ol><h2 id="conseils-d-exploitation" tabindex="-1">Conseils d’exploitation <a class="header-anchor" href="#conseils-d-exploitation" aria-label="Permalink to &quot;Conseils d’exploitation&quot;">​</a></h2><ul><li>Ne laissez pas de session ouverte sur un ordinateur partagé.</li><li>Gardez peu de comptes avec droits administrateur.</li><li>Vérifiez régulièrement les appareils connectés.</li><li>Supprimez les sessions anciennes ou inconnues.</li></ul>',19)])])}const v=n(l,[["render",d]]);export{q as __pageData,v as default};
